import React, { useRef } from 'react';

function FeatureCards() {
  const features = [
    { emoji: '🎧', title: 'Supports Audio & Text', desc: 'Upload MP3, WAV, or TXT files for processing' },
    { emoji: '⚡', title: 'Fast Transcription', desc: 'Get transcribed content in seconds using AI' },
    { emoji: '📚', title: 'Summary Generation', desc: 'Automatically generates key takeaways from the transcript' },
    { emoji: '📝', title: 'Export to Notion', desc: 'Save notes directly to your Notion workspace' },
    { emoji: '📧', title: 'Share via Email', desc: 'Email summary and action items (coming soon)' },
    { emoji: '📋', title: 'Copy Summary', desc: 'Quickly copy the generated summary to clipboard' },
  ];

  const handleTilt = (e, ref) => {
    const card = ref.current;
    const rect = card.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const rotateY = ((x / rect.width) - 0.5) * 25;
    const rotateX = ((y / rect.height) - 0.5) * -25;

    const shadowX = ((x / rect.width) - 0.5) * -30;
    const shadowY = ((y / rect.height) - 0.5) * 30;

    const glowSide = x < rect.width / 2 ? 'left' : 'right';

    card.style.transform = `rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
    card.style.boxShadow = `${shadowX}px ${shadowY}px 25px rgba(0,0,0,0.3)`;

    card.style.borderImageSource = glowSide === 'left'
      ? 'linear-gradient(to right, #f43f5e, transparent)'
      : 'linear-gradient(to left, #3b82f6, transparent)';

    card.style.borderImageSlice = 1;
  };

  const resetTilt = (ref) => {
    const card = ref.current;
    card.style.transform = `rotateX(0deg) rotateY(0deg)`;
    card.style.boxShadow = `none`;
    card.style.borderImageSource = 'none';
  };

  return (
    <section className="w-full max-w-7xl grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {features.map((item, idx) => {
        const cardRef = useRef(null);
        return (
          <div
            key={idx}
            ref={cardRef}
            onMouseMove={(e) => handleTilt(e, cardRef)}
            onMouseLeave={() => resetTilt(cardRef)}
            className="
              relative
              rounded-xl
              border-[0.5px]
              p-6
              shadow-md
              hover:shadow-lg
              transition-transform
              duration-200
              ease-out
              bg-gray-800
              border-4
              border-transparent
              before:absolute
              before:inset-0
              before:rounded-xl
              before:border-[2px]
              before:border-gradient
              before:border-t-pink-500
              before:border-r-yellow-500
              before:border-b-green-500
              before:border-l-blue-500
              before:animate-borderMove
              before:pointer-events-none
              will-change-transform
              tilt-zone
            "
            style={{ transformStyle: 'preserve-3d' }}
          >
            <h3 className="text-lg font-semibold text-teal-400 mb-2">{item.emoji} {item.title}</h3>
            <p className="text-gray-400">{item.desc}</p>
          </div>
        );
      })}
    </section>
  );
}

export default FeatureCards;
